import React from 'react';
import './SubmitLotus.css';

const C = '#8B1538';

// Petal path shapes (base at 0,0, tip pointing up)
const OUTER_PETAL  = 'M 0 0 C -10 -14 -12 -32 0 -52 C 12 -32 10 -14 0 0';
const MID_PETAL    = 'M 0 0 C -7  -10  -8 -22 0 -36 C  8 -22  7 -10 0 0';
const INNER_PETAL  = 'M 0 0 C -4   -7  -5 -14 0 -22 C  5 -14  4  -7 0 0';

const OUTER_ANGLES  = [0, 45, 90, 135, 180, 225, 270, 315];
const MID_ANGLES    = [22.5, 67.5, 112.5, 157.5, 202.5, 247.5, 292.5, 337.5];
const INNER_ANGLES  = [0, 45, 90, 135, 180, 225, 270, 315];

export default function SubmitLotus() {
  return (
    <svg
      className="submit-lotus"
      viewBox="0 0 200 200"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      {/* outer petals */}
      {OUTER_ANGLES.map(a => (
        <path
          key={`o${a}`}
          d={OUTER_PETAL}
          fill="none"
          stroke={C}
          strokeWidth="0.8"
          opacity="0.55"
          transform={`translate(100,100) rotate(${a})`}
        />
      ))}

      {/* mid petals (offset 22.5°) */}
      {MID_ANGLES.map(a => (
        <path
          key={`m${a}`}
          d={MID_PETAL}
          fill="none"
          stroke={C}
          strokeWidth="0.8"
          opacity="0.4"
          transform={`translate(100,100) rotate(${a})`}
        />
      ))}

      {/* inner petals */}
      {INNER_ANGLES.map(a => (
        <path
          key={`i${a}`}
          d={INNER_PETAL}
          fill="none"
          stroke={C}
          strokeWidth="0.7"
          opacity="0.3"
          transform={`translate(100,100) rotate(${a})`}
        />
      ))}

      {/* centre */}
      <circle cx="100" cy="100" r="5" fill="none" stroke={C} strokeWidth="0.8" opacity="0.5" />
      <circle cx="100" cy="100" r="2" fill={C} opacity="0.4" />
    </svg>
  );
}
